import { useState } from 'react';
import axios from 'axios';

function App() {
    const [resume, setResume] = useState(null);
    const [photo, setPhoto] = useState(null);
    const [jobDesc, setJobDesc] = useState('');
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async () => {
        if (!resume) return setError('Please upload a resume PDF.');
        setError('');
        setLoading(true);
        const formData = new FormData();
        formData.append('resume', resume);
        if (photo) formData.append('photo', photo);
        if (jobDesc) formData.append('jobDescription', jobDesc);

        try {
            const res = await axios.post('http://localhost:5000/analyze', formData);
            setResult(res.data);
        } catch (err) {
            setError(err.response?.data?.error || 'Something went wrong.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ maxWidth: 700, margin: '40px auto', fontFamily: 'sans-serif', padding: 20 }}>
            <h1>📄 Resume Analyzer</h1>

            <div style={{ marginBottom: 16 }}>
                <label>Resume (PDF) *</label><br />
                <input type="file" accept=".pdf" onChange={e => setResume(e.target.files[0])} />
            </div>

            <div style={{ marginBottom: 16 }}>
                <label>Photo (optional)</label><br />
                <input type="file" accept="image/*" onChange={e => setPhoto(e.target.files[0])} />
            </div>

            <div style={{ marginBottom: 16 }}>
                <label>Job Description (optional)</label><br />
                <textarea rows={5} style={{ width: '100%' }} value={jobDesc}
                    onChange={e => setJobDesc(e.target.value)}
                    placeholder="Paste the job description here for targeted ATS scoring..." />
            </div>

            {error && <p style={{ color: 'red' }}>{error}</p>}

            <button onClick={handleSubmit} disabled={loading}
                style={{ padding: '10px 24px', fontSize: 16, cursor: 'pointer', background: '#2563eb', color: '#fff', border: 'none', borderRadius: 6 }}>
                {loading ? 'Analyzing...' : 'Analyze Resume'}
            </button>

            {result && (
                <div style={{ marginTop: 32 }}>
                    {result.photoUrl && (
                        <img src={`http://localhost:5000${result.photoUrl}`} alt="Profile"
                            style={{ width: 80, height: 80, borderRadius: '50%', marginBottom: 16 }} />
                    )}
                    <h2>ATS Score: {result.analysis.ats_score} / 100</h2>
                    <div style={{ background: '#e5e7eb', borderRadius: 8, height: 16, marginBottom: 24 }}>
                        <div style={{ width: `${result.analysis.ats_score}%`, background: '#2563eb', height: 16, borderRadius: 8 }} />
                    </div>

                    <h3>✅ Skills Found</h3>
                    <p>{result.analysis.skills_found?.join(', ')}</p>

                    <h3>❌ Missing Keywords</h3>
                    <p>{result.analysis.missing_keywords?.join(', ')}</p>

                    <h3>💪 Strengths</h3>
                    <ul>{result.analysis.strengths?.map((s, i) => <li key={i}>{s}</li>)}</ul>

                    <h3>💡 Recommendations</h3>
                    <ul>{result.analysis.recommendations?.map((r, i) => <li key={i}>{r}</li>)}</ul>

                    <h3>📝 Summary</h3>
                    <p>{result.analysis.overall_summary}</p>
                </div>
            )}
        </div>
    );
}

export default App;
